VALUES
  ('real-estate-moex-00194', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其所有之名畫出租於乙，並未將代理權授與乙。詎料，乙竟以甲之代理人名義，與善意之丙 訂立買賣契約，將名畫出賣並交付於丙。甲不承認乙之無權代理行為，下列敘述，何者正確？', '["丙善意取得名畫之所有權", "丙得請求乙損害賠償", "乙與丙之買賣契約有效", "乙與丙之物權契約有效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00195', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲對乙有新臺幣（下同）100萬元之債權，將該債權讓與丙，甲與丙均未通知乙債權讓與之事情。 嗣後，乙因不知債權讓與之事情，對甲清償100萬元，經甲受領，下列敘述，何者正確？', '["甲與丙之債權讓與無效", "乙之債務因清償而消滅", "應經丙承認，乙之債務始消滅", "甲與丙之債權讓與應經乙承認始生效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00196', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲申請之建案因違法無法取得建造許可，遂與乙約定，由甲贈與乙之妻丙100萬元後，乙須幫助 甲取得建造許可，後來乙收賄之行為經法院判決有罪確定。問甲可否向丙請求返還100萬元？', '["可以，依據不當得利", "不可，100萬元為不法原因之給付", "可以，100萬為違背公序良俗之給付", "可以，依據無因管理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00197', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲無權占有乙所有已登記之A地15年後，乙對甲提起所有物返還請求之訴訟，下列敘述，何者 正確？', '["甲得對乙為消滅時效之抗辯", "乙之回復請求權不罹於消滅時效", "甲得對乙主張時效取得A地所有權", "乙之A地所有權因罹於時效而消滅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00198', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與乙訂立租賃契約，將丙所有之A屋出租於乙，並交付於乙。嗣後，丙對乙起訴，請求乙返還 A屋，致乙不能為約定之使用，下列敘述，何者正確？', '["甲與乙訂立之租賃契約無效", "甲與乙訂立之租賃契約得撤銷", "乙得終止與甲訂立之租賃契約", "乙得以與甲之租賃契約對抗丙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00199', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其所有之A屋出租於乙，乙未經甲之同意，將A屋全部轉租於丙。下列敘述，何者正確？', '["乙與丙訂立之租賃契約無效", "甲與乙訂立之租賃契約無效", "乙得終止乙與丙之租賃契約", "甲得終止甲與乙之租賃契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00200', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲在其所有之A地上興建B屋後，將B屋出售並移轉所有權登記於乙。下列敘述，何者正確？', '["推定甲與乙在房屋得使用期限內有租賃關係", "視為甲與乙在房屋得使用期限內有租賃關係", "推定乙在房屋得使用期限內對A地有普通地上權", "視為乙在房屋得使用期限內對A地有普通地上權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00201', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '有關意思表示之敘述，下列何者正確？', '["甲與乙本為夫妻，為逃避債務，通謀虛偽離婚，並辦理離婚登記完畢，甲乙間已無婚姻關係", "甲無欲為其意思表示之拘束，而向乙表示將贈與新款手機一部，乙雖明知甲心中之真意，贈與 契約仍有效", "甲誤將丙誤認為乙，與之訂立買賣契約，該契約有效，但甲得撤銷其之意思表示", "甲受丙脅迫而與之訂立互易契約，該契約當然無效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00202', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與其20歲之兒子乙訂立贈與契約，將甲所有之A屋贈與乙，並完成所有權移轉登記。嗣後， 乙竟不履行對甲之法定扶養義務。下列敘述，何者正確？', '["甲得解除贈與契約", "甲得終止贈與契約", "甲得撤銷贈與契約", "甲得撤回贈與契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00203', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲於自有土地上建造房屋一棟，因積欠乙銀行巨款，土地及房屋遭乙向法院聲請查封拍賣，土地 為丙所拍得，房屋為丁所拍得。下列敘述，何者正確？', '["丙可以請求丁拆屋還地", "丁必須承租丙之土地", "視為丁於土地上有地上權", "推定丙與丁間有使用借貸契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00204', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與乙訂立買賣契約，向乙購買A地。下列關於甲何時取得A地所有權之敘述，何者正確？', '["買賣契約有效成立時", "甲付清買賣價金之時", "完成所有權移轉登記時", "乙將A地交付於甲之時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00205', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙丙丁分別共有A地，甲以乙丙丁為被告提起分割共有物之訴，獲得勝訴確定判決。下列敘述， 何者正確？', '["甲乙丙丁於判決確定時，各自取得分得部分之所有權", "甲根據確定判決，請求乙丙丁辦理登記，始取得分得部分之所有權", "共有物分割之判決是確認判決，僅在確認甲乙丙丁之權利義務法律關係", "共有物分割之判決是給付判決，甲有權請求乙丙丁給付分得部分之所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00206', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲以行使普通地上權之意思，二十年間和平、公然、繼續在乙已登記之 A 地上有 B 屋，下列敘 述，何者正確？', '["甲已經取得普通地上權", "甲得請求登記為普通地上權人", "因乙之A地已辦理登記，故甲無法時效取得", "甲得直接以乙為被告，起訴請求乙同意甲登記為普通地上權人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00207', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲以自有土地設定抵押權予乙，以擔保其債權，該債權之請求權於113年3月1日因時效而消滅。 下列敘述，何者正確？', '["因從屬於擔保債權，故抵押權隨之消滅", "抵押權人須於消滅時效完成後，5年間實行其抵押權", "抵押權無消滅時效，可一直存續", "從此之後，抵押權之實行須經債務人同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00208', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲向乙銀行貸款新臺幣500萬元，並以甲所有之A地為乙設定普通抵押權，雙方約定債權已屆清 償期而未為清償時，A地之所有權移屬於乙。就該流押契約之效力，下列敘述，何者正確？', '["絕對無效", "相對無效", "非經登記，不生效力", "非經登記，不得對抗第三人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
