  ('real-estate-moex-00210', 'real-estate', 'real-estate-moex-113-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '著有數本暢銷理財專書之甲，某日遭汽車駕駛人丙撞傷，卻於與丙損害賠償協議達成前，突發心 肌梗塞猝死，留有土地一筆及尚未繳清貸款之房屋一棟，某上市電子公司股份100萬股，銀行存 款30萬元，尚欠有乙銀行之信用貸款20萬元。下列何者非屬繼承之標的？', '["尚未繳清貸款之房屋", "甲所著理財專書之著作權", "甲對丙依據民法第195條規定可主張之非財產上損害賠償請求權", "甲積欠乙銀行之20萬信用貸款"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:33+00:00", "source_pdf_sha1": "326f92027184", "answer_pdf_sha1": "a024a70a8d12", "source_family": "moex-gov-tw", "moex": {"exam_code": "113190", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL);
